// SLOW TICK: Performs all fast-tick steps PLUS additional slow-tick steps:
//   - Activity transition
//   - Routine event generation
//   - Desire generation (from drives above impulse threshold)
//   - Desire lifecycle management (aging, persistence, crystallization)

let state = $getWorkflowStaticData('global').agentState;
if (!state) {
  return [{ json: { skip: true, reason: 'No agent state initialized.' } }];
}

state.tick_counter = (state.tick_counter || 0) + 1;

const episodicLog = $getWorkflowStaticData('global').episodicLog || [];
const lastSlowTick = $getWorkflowStaticData('global').lastSlowTick || 0;
const now = Date.now();

// Gather world events since last slow tick
const recentEvents = episodicLog.filter(e => {
  const t = new Date(e.created_at).getTime();
  return t > lastSlowTick;
});

const worldEvents = [];
const conversationCount = recentEvents.filter(e => e.type === 'user_interaction').length;
if (conversationCount > 0) {
  worldEvents.push({ type: 'conversation', count: conversationCount });
}

$getWorkflowStaticData('global').lastSlowTick = now;

return [{
  json: {
    state,
    world_events: worldEvents,
    activity_events: worldEvents,
    cycle_id: `slow-${state.tick_counter}`,
    cycle_type: 'slow_tick',
    timestamp: new Date().toISOString()
  }
}];

// FAST-TICK STEPS: Appraise → Emotion → Drives → Thought → Salience → Goals → Write
// Condensed into one Code node for the slow tick (same logic as fast_tick_cycle.json)

const item = $input.first().json;
const state = item.state;
const worldEvents = item.world_events || [];
const activityEvents = item.activity_events || [];
const tick = state.tick_counter || 0;

// ── APPRAISE ──
const appraisals = worldEvents.map(e => ({
  goal_congruence: e.type === 'conversation' ? 0.2 : 0,
  threat: 0,
  arousal_cue: e.type === 'conversation' ? 0.1 : 0
}));

// ── UPDATE EMOTION ──
function ema(v, b, r) { return v + (b - v) * r; }
function clamp(v, lo = -1, hi = 1) { return Math.max(lo, Math.min(hi, v)); }

const baseline = { valence: 0.10, arousal: 0.30, stress: 0.10, energy: 0.70 };
const decay = { valence: 0.05, arousal: 0.08, stress: 0.06, energy: 0.04 };

let valence = ema(state.affect.valence, baseline.valence, decay.valence);
let arousal = ema(state.affect.arousal, baseline.arousal, decay.arousal);
let stress = ema(state.affect.stress, baseline.stress, decay.stress);
let energy = ema(state.affect.energy, baseline.energy, decay.energy);

const ticksPerDay = 48;
const phase = (2 * Math.PI * ((tick % ticksPerDay) - 20)) / ticksPerDay;
energy += 0.15 * Math.cos(phase);

for (const a of appraisals) {
  valence += (a.goal_congruence || 0) * 0.10;
  stress += (a.threat || 0) * 0.10;
  arousal += (a.arousal_cue || 0) * 0.05;
}

state.affect = { valence: clamp(valence), arousal: clamp(arousal), stress: clamp(stress), energy: clamp(energy) };
const restBoost = stress > 0.70 ? 0.01 : 0.0;

// ── UPDATE DRIVES ──
const DRIVE_NAMES = ['social_need', 'mastery_need', 'rest_need', 'curiosity'];
const growthRates = { social_need: 0.04, mastery_need: 0.02, rest_need: 0.03, curiosity: 0.01 };
const satMap = {
  social_need: { by: ['conversation'], r: 0.25 },
  mastery_need: { by: ['goal_progress', 'task_completion'], r: 0.20 },
  rest_need: { by: ['sleep'], r: 0.40 },
  curiosity: { by: ['reading', 'exploring_topic'], r: 0.30 }
};

for (const d of DRIVE_NAMES) state.drives[d] += growthRates[d] || 0;
state.drives.rest_need += restBoost;
const eventTypes = activityEvents.map(e => e.type || '');
for (const d of DRIVE_NAMES) {
  const s = satMap[d];
  if (s) for (const t of eventTypes) if (s.by.includes(t)) state.drives[d] -= s.r;
}
for (const d of DRIVE_NAMES) state.drives[d] = Math.max(0, Math.min(1, state.drives[d]));

// ── GENERATE THOUGHT ──
const templates = {
  reflection: ['Thinking about what matters most right now.', 'Noticing patterns in how things have been going lately.'],
  planning: ['Thinking through what needs to happen next.', 'Mapping out steps to move something forward.'],
  social: ['Thinking about someone I\'d like to reach out to.', 'Feeling the pull of wanting to connect.'],
  curiosity: ['Wondering about something I don\'t fully understand yet.', 'Something unfamiliar has caught my attention.']
};
let category = 'reflection';
if (state.affect.valence < -0.3) category = 'rumination';
else if (state.drives.social_need > 0.5) category = 'social';
else if (state.affect.arousal > 0.6) category = state.drives.curiosity > state.drives.mastery_need ? 'curiosity' : 'planning';

const catTemplates = templates[category] || templates.reflection;
const thought = { id: `thought-slow-${tick}`, text: catTemplates[tick % catTemplates.length], thought_category: category };

// ── UPDATE GOALS ──
state.goals = (state.goals || []).map(g => {
  if (g.status !== 'active') return g;
  const stalled = (g.blocked_by || []).length > 0;
  let p = g.progress, f = g.frustration, s = g.status;
  if (stalled) f = Math.min(1, f + 0.05); else { p = Math.min(1, p + 0.01); f = Math.max(0, f - 0.10); }
  if (f >= 0.75) s = 'suspended';
  return { ...g, progress: Math.round(p * 1e4) / 1e4, frustration: Math.round(f * 1e4) / 1e4, status: s };
});

return [{ json: { ...item, state, thought, appraisals } }];

// SLOW-TICK STEP: ACTIVITY_TRANSITION
// Determine if the persona should change their current activity.

const item = $input.first().json;
const state = item.state;

// Simple activity transition logic (replace with LLM-driven in production)
const drives = state.drives;
let newActivity = state.activity.current_activity;

if (drives.rest_need > 0.7) {
  newActivity = 'resting';
} else if (drives.social_need > 0.6) {
  newActivity = 'seeking_connection';
} else if (drives.mastery_need > 0.6) {
  newActivity = 'working_on_goal';
} else if (drives.curiosity > 0.7) {
  newActivity = 'exploring';
} else {
  newActivity = 'idle';
}

state.activity.current_activity = newActivity;

return [{ json: { ...item, state } }];

// SLOW-TICK STEP: ROUTINE_EVENT
// Generate synthetic routine events based on current activity.

const item = $input.first().json;
const state = item.state;
const activity = state.activity.current_activity;

const routineEvents = [];

// Map activity to event types for drive satisfaction
const activityToEvents = {
  resting: [{ type: 'low_arousal_idle_period' }],
  seeking_connection: [{ type: 'social_activity' }],
  working_on_goal: [{ type: 'goal_progress' }],
  exploring: [{ type: 'exploring_topic' }],
  reading: [{ type: 'reading' }],
  idle: []
};

routineEvents.push(...(activityToEvents[activity] || []));

return [{ json: { ...item, state, routine_events: routineEvents } }];

// SLOW-TICK STEP: DESIRE_GENERATION
// Generate ephemeral desires when drives exceed impulse thresholds.
// Manage desire lifecycle: aging, persistence, crystallization into goals.

const item = $input.first().json;
const state = item.state;
const tick = state.tick_counter;

const DRIVE_NAMES = ['social_need', 'mastery_need', 'rest_need', 'curiosity'];
const impulseThreshold = { social_need: 0.65, mastery_need: 0.70, rest_need: 0.70, curiosity: 0.75 };
const contentTemplates = {
  social_need: 'want to connect with someone',
  mastery_need: 'want to work on something meaningful',
  rest_need: 'want to slow down and rest',
  curiosity: 'want to explore something new'
};

// 1. Generate new desires
const newDesires = [];
for (const d of DRIVE_NAMES) {
  const value = state.drives[d];
  if (value >= (impulseThreshold[d] || 1.0)) {
    newDesires.push({
      id: `desire-${d}-${tick}`,
      source_drive: d,
      urgency: Math.round(value * 10000) / 10000,
      approach: true,
      expires_after_ticks: 3,
      age_in_ticks: 0,
      created_at_tick: tick,
      content: `${contentTemplates[d]} (intensity ${value.toFixed(2)})`
    });
  }
}
state.active_desires = newDesires;

// 2. Age and expire persisted desires
let persisted = (state.persisted_desires || []).map(d => ({
  ...d, age_in_ticks: (d.age_in_ticks || 0) + 1
})).filter(d => d.age_in_ticks < (d.expires_after_ticks || 3));

// 3. Persist high-urgency new desires
const persistenceThreshold = 0.50;
const toPersist = newDesires.filter(d => d.urgency >= persistenceThreshold);
const byDrive = {};
for (const d of [...persisted, ...toPersist]) {
  const drive = d.source_drive;
  if (!byDrive[drive] || d.urgency > byDrive[drive].urgency) byDrive[drive] = d;
}
persisted = Object.values(byDrive);
state.persisted_desires = persisted;

// 4. Check crystallization: desires old enough → propose new goals
const crystallizationThreshold = 6;
const urgencyMin = 0.65;
const dampen = 0.60;
const activeDriveGoals = new Set(
  (state.goals || []).filter(g => g.status === 'active' && g.crystallized_from_drive).map(g => g.crystallized_from_drive)
);

const goalProposals = [];
const proposedDrives = new Set();
for (const desire of persisted) {
  const drive = desire.source_drive;
  if (proposedDrives.has(drive) || desire.age_in_ticks < crystallizationThreshold) continue;
  if (desire.urgency < urgencyMin || activeDriveGoals.has(drive)) continue;

  goalProposals.push({
    id: `goal-${drive}-${desire.id}`,
    label: `Address ${drive.replace(/_/g, ' ')}`,
    motive: drive,
    priority: Math.round(desire.urgency * dampen * 10000) / 10000,
    horizon: 'short',
    progress: 0.0,
    frustration: 0.0,
    status: 'active',
    crystallized_from_drive: drive,
    crystallized_at: `tick:${desire.created_at_tick}`,
    created_at: new Date().toISOString(),
    blocked_by: []
  });
  proposedDrives.add(drive);
}

// Accept proposals if under max active goals (8)
const maxGoals = 8;
const activeCount = (state.goals || []).filter(g => g.status === 'active').length;
for (const proposal of goalProposals) {
  if (activeCount + goalProposals.indexOf(proposal) >= maxGoals) break;
  if (!activeDriveGoals.has(proposal.crystallized_from_drive)) {
    state.goals.push(proposal);
  }
}

return [{ json: { ...item, state, new_desires: newDesires.length, crystallized_goals: goalProposals.length } }];

// WRITE & LOG — persist state and write episodic memory
const item = $input.first().json;
const state = item.state;
const thought = item.thought;

// Write thought to episodic log
if (thought) {
  const log = $getWorkflowStaticData('global').episodicLog || [];
  log.push({
    id: thought.id,
    type: 'thought',
    text: thought.text,
    thought_category: thought.thought_category,
    importance: 0.3,
    similarity: 0,
    recency: 1.0,
    self_relevance: 0.2,
    created_at: new Date().toISOString(),
    lifecycle_state: 'active',
    affect_snapshot: { ...state.affect },
    drive_snapshot: { ...state.drives }
  });
  if (log.length > 200) log.splice(0, log.length - 200);
  $getWorkflowStaticData('global').episodicLog = log;
}

// Persist state
state.attention = { current_focus: null, salience_buffer: [] };
state.active_desires = [];
$getWorkflowStaticData('global').agentState = state;

return [{
  json: {
    cycle_id: item.cycle_id,
    cycle_type: 'slow_tick',
    tick_counter: state.tick_counter,
    activity: state.activity.current_activity,
    new_desires: item.new_desires || 0,
    crystallized_goals: item.crystallized_goals || 0,
    total_goals: state.goals.length,
    affect: state.affect,
    drives: state.drives,
    timestamp: new Date().toISOString()
  }
}];
